<?php namespace App\Domains\Tourism\Policies; use Illuminate\Auth\Access\HandlesAuthorization; class PackagePolicy { use HandlesAuthorization; public function viewAny($user) { return true; } public function view($user, $package) { return $user->tenant_id === $package->tenant_id; } public function create($user) { return true; } public function update($user, $package) { return $user->tenant_id === $package->tenant_id; } public function delete($user, $package) { return $user->tenant_id === $package->tenant_id; } }
